import { useState, useEffect, useCallback, useRef } from 'react';
import io from 'socket.io-client';
import { supabase } from '../services/supabase';

export const useLocation = (userId, userName, userUuid, avatarColor) => {
    const [users, setUsers] = useState([]);
    const [currentLocation, setCurrentLocation] = useState(null);
    const [isConnected, setIsConnected] = useState(false);
    const [error, setError] = useState(null);
    const [nearbyUsers, setNearbyUsers] = useState([]);

    const socketRef = useRef(null);
    const watchIdRef = useRef(null);

    useEffect(() => {
        if (!userId) return;

        const serverUrl = process.env.REACT_APP_SERVER_URL || 'http://localhost:5000';
        socketRef.current = io(serverUrl, {
            transports: ['websocket', 'polling'],
            reconnection: true,
            reconnectionAttempts: 5,
            reconnectionDelay: 1000
        });

        const socket = socketRef.current;

        socket.on('connect', () => {
            console.log('Connected to server');
            setIsConnected(true);
            socket.emit('register-user', {
                userId,
                userUuid,
                displayName: userName,
                avatarColor
            });
        });

        socket.on('disconnect', () => {
            console.log('Disconnected from server');
            setIsConnected(false);
        });

        socket.on('initial-locations', (locations) => {
            console.log('Initial locations:', locations);
            setUsers(locations.filter(loc => loc.user_id !== userId));
        });

        socket.on('location-updated', (location) => {
            if (location.userId !== userId) {
                setUsers(prev => {
                    const filtered = prev.filter(u => u.user_id !== location.userId);
                    return [...filtered, {
                        user_id: location.userId,
                        user_name: location.userName,
                        latitude: location.latitude,
                        longitude: location.longitude,
                        accuracy: location.accuracy,
                        last_update: location.timestamp,
                        avatarColor: location.avatarColor,
                        users: location.userUuid ? {
                            id: location.userUuid,
                            display_name: location.userName,
                            avatar_color: location.avatarColor
                        } : null
                    }];
                });
            }
        });

        socket.on('user-online', ({ userId: onlineUserId, displayName, avatarColor: color }) => {
            console.log('User online:', onlineUserId, displayName);
        });

        socket.on('user-offline', ({ userId: offlineUserId }) => {
            setUsers(prev => prev.filter(u => u.user_id !== offlineUserId));
        });

        socket.on('error', (error) => {
            console.error('Socket error:', error);
            setError(error.message);
        });

        return () => {
            if (socket) {
                socket.disconnect();
            }
        };
    }, [userId, userUuid, userName, avatarColor]);

    const updateLocationDB = useCallback(async (latitude, longitude, accuracy) => {
        try {
            const payload = {
                user_id: userId,
                user_name: userName,
                latitude,
                longitude,
                accuracy,
                last_update: new Date().toISOString(),
                is_active: true
            };
            if (userUuid) payload.user_uuid = userUuid;

            const { error } = await supabase
                .from('locations')
                .upsert(payload, { onConflict: 'user_id' });

            if (error) throw error;
        } catch (err) {
            console.error('Error updating location in DB:', err);
        }
    }, [userId, userName, userUuid]);

    useEffect(() => {
        if (!userId || !socketRef.current) return;

        const startWatching = () => {
            if (!navigator.geolocation) {
                setError('Geolocation is not supported');
                return;
            }

            watchIdRef.current = navigator.geolocation.watchPosition(
                (position) => {
                    const { latitude, longitude, accuracy } = position.coords;
                    const locationData = { latitude, longitude, accuracy };
                    setCurrentLocation(locationData);

                    if (socketRef.current && socketRef.current.connected) {
                        socketRef.current.emit('update-location', {
                            userId,
                            userName,
                            latitude,
                            longitude,
                            accuracy,
                            userUuid,
                            avatarColor
                        });
                    }

                    updateLocationDB(latitude, longitude, accuracy);
                },
                (err) => {
                    console.error('Geolocation error:', err);
                    setError(`GPS Error: ${err.message}`);
                },
                {
                    enableHighAccuracy: true,
                    maximumAge: 0,
                    timeout: 10000
                }
            );
        };

        startWatching();

        return () => {
            if (watchIdRef.current) {
                navigator.geolocation.clearWatch(watchIdRef.current);
            }
        };
    }, [userId, userName, userUuid, avatarColor, updateLocationDB]);

    const getNearbyUsers = useCallback((latitude, longitude, radius = 20037) => {
        if (socketRef.current && socketRef.current.connected) {
            socketRef.current.emit('request-nearby', { latitude, longitude, radiusKm: radius });
        }
    }, []);

    useEffect(() => {
        if (!socketRef.current) return;

        socketRef.current.on('nearby-users', (users) => {
            setNearbyUsers(users);
        });

        return () => {
            if (socketRef.current) {
                socketRef.current.off('nearby-users');
            }
        };
    }, []);

    useEffect(() => {
        const handleBeforeUnload = async () => {
            if (socketRef.current) {
                socketRef.current.disconnect();
            }
            await supabase
                .from('locations')
                .update({ is_active: false })
                .eq('user_id', userId);
        };

        window.addEventListener('beforeunload', handleBeforeUnload);

        return () => {
            window.removeEventListener('beforeunload', handleBeforeUnload);
        };
    }, [userId]);

    return {
        users,
        currentLocation,
        nearbyUsers,
        isConnected,
        error,
        getNearbyUsers
    };
};
